// OnConflict allows configuring the `ON CONFLICT` / `ON DUPLICATE KEY` clause
// of the `INSERT` statement. For example:
//
//	client.UpstreamEvent.CreateBulk(builders...).
//		OnConflict(
//			// Update the row with the new values
//			// the was proposed for insertion.
//			sql.ResolveWithNewValues(),
//		).
//		// Override some of the fields with custom
//		// update values.
//		Update(func(u *ent.UpstreamEventUpsert) {
//			SetUpstreamConfigID(v+v).
//		}).
//		Exec(ctx)
func (_c *UpstreamEventCreateBulk) OnConflict(opts ...sql.ConflictOption) *UpstreamEventUpsertBulk {
	_c.conflict = opts
	return &UpstreamEventUpsertBulk{
		create: _c,
	}
}

// OnConflictColumns calls `OnConflict` and configures the columns
// as conflict target. Using this option is equivalent to using:
//
//	client.UpstreamEvent.Create().
//		OnConflict(sql.ConflictColumns(columns...)).
//		Exec(ctx)
func (_c *UpstreamEventCreateBulk) OnConflictColumns(columns ...string) *UpstreamEventUpsertBulk {
	_c.conflict = append(_c.conflict, sql.ConflictColumns(columns...))
	return &UpstreamEventUpsertBulk{
		create: _c,
	}
}

// UpstreamEventUpsertBulk is the builder for "upsert"-ing
// a bulk of UpstreamEvent nodes.
type UpstreamEventUpsertBulk struct {
	create *UpstreamEventCreateBulk
}

// UpdateNewValues updates the mutable fields using the new values that
// were set on create. Using this option is equivalent to using:
//
//	client.UpstreamEvent.Create().
//		OnConflict(
//			sql.ResolveWithNewValues(),
//		).
//		Exec(ctx)
func (u *UpstreamEventUpsertBulk) UpdateNewValues() *UpstreamEventUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithNewValues())
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(s *sql.UpdateSet) {
		for _, b := range u.create.builders {
			if _, exists := b.mutation.UpstreamConfigID(); exists {
				s.SetIgnore(upstreamevent.FieldUpstreamConfigID)
			}
			if _, exists := b.mutation.UpstreamKeyID(); exists {
				s.SetIgnore(upstreamevent.FieldUpstreamKeyID)
			}
			if _, exists := b.mutation.SyncRunID(); exists {
				s.SetIgnore(upstreamevent.FieldSyncRunID)
			}
			if _, exists := b.mutation.AccountID(); exists {
				s.SetIgnore(upstreamevent.FieldAccountID)
			}
			if _, exists := b.mutation.EventKey(); exists {
				s.SetIgnore(upstreamevent.FieldEventKey)
			}
			if _, exists := b.mutation.EventType(); exists {
				s.SetIgnore(upstreamevent.FieldEventType)
			}
			if _, exists := b.mutation.Severity(); exists {
				s.SetIgnore(upstreamevent.FieldSeverity)
			}
			if _, exists := b.mutation.Source(); exists {
				s.SetIgnore(upstreamevent.FieldSource)
			}
			if _, exists := b.mutation.Message(); exists {
				s.SetIgnore(upstreamevent.FieldMessage)
			}
			if _, exists := b.mutation.Payload(); exists {
				s.SetIgnore(upstreamevent.FieldPayload)
			}
			if _, exists := b.mutation.OccurredAt(); exists {
				s.SetIgnore(upstreamevent.FieldOccurredAt)
			}
			if _, exists := b.mutation.CreatedAt(); exists {
				s.SetIgnore(upstreamevent.FieldCreatedAt)
			}
		}
	}))
	return u
}

// Ignore sets each column to itself in case of conflict.
// Using this option is equivalent to using:
//
//	client.UpstreamEvent.Create().
//		OnConflict(sql.ResolveWithIgnore()).
//		Exec(ctx)
func (u *UpstreamEventUpsertBulk) Ignore() *UpstreamEventUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithIgnore())
	return u
}

// DoNothing configures the conflict_action to `DO NOTHING`.
// Supported only by SQLite and PostgreSQL.
func (u *UpstreamEventUpsertBulk) DoNothing() *UpstreamEventUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.DoNothing())
	return u
}

// Update allows overriding fields `UPDATE` values. See the UpstreamEventCreateBulk.OnConflict
// documentation for more info.
func (u *UpstreamEventUpsertBulk) Update(set func(*UpstreamEventUpsert)) *UpstreamEventUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&UpstreamEventUpsert{UpdateSet: update})
	}))
	return u
}

// Exec executes the query.
func (u *UpstreamEventUpsertBulk) Exec(ctx context.Context) error {
	if u.create.err != nil {
		return u.create.err
	}
	for i, b := range u.create.builders {
		if len(b.conflict) != 0 {
			return fmt.Errorf("ent: OnConflict was set for builder %d. Set it on the UpstreamEventCreateBulk instead", i)
		}
	}
	if len(u.create.conflict) == 0 {
		return errors.New("ent: missing options for UpstreamEventCreateBulk.OnConflict")
	}
	return u.create.Exec(ctx)
}

// ExecX is like Exec, but panics if an error occurs.
func (u *UpstreamEventUpsertBulk) ExecX(ctx context.Context) {
	if err := u.create.Exec(ctx); err != nil {
		panic(err)
	}
}
